# Terraform: ALZ management group hierarchy (AzureRM provider)
# An alternative to ALZ-Bicep for teams already using Terraform.
# Uses azurerm_management_group resources.

# management_groups.tf
cat > management_groups.tf << 'EOF'
variable "tenant_id" { type = string }
variable "root_parent_id" { type = string }  # tenant root MG id

resource "azurerm_management_group" "alz" {
  display_name               = "Azure Landing Zones"
  parent_management_group_id = "/providers/Microsoft.Management/managementGroups/${var.root_parent_id}"
}

resource "azurerm_management_group" "platform" {
  display_name               = "Platform"
  parent_management_group_id = azurerm_management_group.alz.id
}

resource "azurerm_management_group" "platform_connectivity" {
  display_name               = "Connectivity"
  parent_management_group_id = azurerm_management_group.platform.id
}

resource "azurerm_management_group" "platform_identity" {
  display_name               = "Identity"
  parent_management_group_id = azurerm_management_group.platform.id
}

resource "azurerm_management_group" "platform_management" {
  display_name               = "Management"
  parent_management_group_id = azurerm_management_group.platform.id
}

resource "azurerm_management_group" "landing_zones" {
  display_name               = "Landing Zones"
  parent_management_group_id = azurerm_management_group.alz.id
}

resource "azurerm_management_group" "lz_corp" {
  display_name               = "Corp"
  parent_management_group_id = azurerm_management_group.landing_zones.id
}

resource "azurerm_management_group" "lz_online" {
  display_name               = "Online"
  parent_management_group_id = azurerm_management_group.landing_zones.id
}

resource "azurerm_management_group" "sandbox" {
  display_name               = "Sandbox"
  parent_management_group_id = azurerm_management_group.alz.id
}

resource "azurerm_management_group" "decommissioned" {
  display_name               = "Decommissioned"
  parent_management_group_id = azurerm_management_group.alz.id
}
EOF

terraform init && terraform plan -out=alz.tfplan
terraform apply alz.tfplan
